#include<bits/stdc++.h>
using namespace std;

char a[55],temp;

int main()
{  
	int i,len;
	scanf("%s",a);
	len=strlen(a);
     for(int i=0;i<=len;i++)
     {
     	if(a[i]>='a'&&a[i]<='z')
     	{
     		temp=a[i];
     		temp+=3;
     		if(temp>122)
     		{
     			temp=temp-26;
     		}
    		temp=temp-32;
     		a[i]=temp;
     	}
     	else if(a[i]>='A'&&a[i]<='Z')
     	{
     		temp=a[i];
     		temp+=3;
     		if(temp>90)
     		{
     			temp=temp-26;
     		}
    		temp=temp+32;
     		a[i]=temp;
     	}
     }
     for(int j=len-1;j>=0;j--)
     {
     	printf("%c",a[j]);
     }
     printf("\n");
    return 0;
}
